225→    /** See [ensureOpen]. This must only be run inside the queue. */
226→    private fun ensureOpenInner() {
227→        ensureBackendInner()
228→        if (emulateOpenFailure) {
229→            throw BackendException.BackendDbException.BackendDbLockedException(backendError {})
230→        }
231→        if (collection == null || collection!!.dbClosed) {
232→            val path = collectionPathInValidFolder()
233→            collection =
234→                collection(path, log = !disableLogFile, backend)
235→        }
236→    }
